import java.nio.ByteBuffer;
import java.nio.channels.FileChannel;
import java.nio.file.Paths;
import java.nio.file.StandardOpenOption;

public class Main {
  public static void main(String[] args) throws Exception {
    String message = "Salam, NIO!";
    ByteBuffer buffer = ByteBuffer.allocate(1024);
    buffer.put(message.getBytes());
    buffer.flip();
    try (FileChannel channel = FileChannel.open(Paths.get("output.txt"), StandardOpenOption.CREATE, StandardOpenOption.WRITE)) {
      channel.write(buffer);
    }
    System.out.println("Fayla yazıldı: " + message);
  }
}
// Çıxış: Fayla yazıldı: Salam, NIO!

